import{_ as e,o as s,c as i,a2 as o}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Super Admin","description":"","frontmatter":{},"headers":[],"relativePath":"pt/features/super-admin.md","filePath":"pt/features/super-admin.md"}'),t={name:"pt/features/super-admin.md"};function r(d,a,n,l,c,p){return s(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="super-admin" tabindex="-1">Super Admin <a class="header-anchor" href="#super-admin" aria-label="Permalink to &quot;Super Admin&quot;">​</a></h1><p>O papel <code>super_admin</code> é criado automaticamente pelo <code>clearance:install</code> e mantido sincronizado com todas as permissões <code>clearance-*</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>Ver o <a href="/clearance-docs/pt/guide/installation.html">guia de Instalação</a> e a <a href="/clearance-docs/pt/api/artisan-commands.html">referência de comandos Artisan</a> para a lista completa de flags do instalador.</p><h2 id="bypass-da-gate-opcional" tabindex="-1">Bypass da Gate (opcional) <a class="header-anchor" href="#bypass-da-gate-opcional" aria-label="Permalink to &quot;Bypass da Gate (opcional)&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> controla se o papel <code>super_admin</code> contorna todas as verificações <code>can()</code> / <code>Gate::allows()</code> / política do Laravel globalmente, através de um hook <code>Gate::before()</code>. Padrão: <code>false</code>. O bypass é opcional. Para o ativar:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Aplicado a toda a aplicação, não delimitado ao painel</p><p>Quando ativado, qualquer utilizador que detenha <code>super_admin</code> salta <strong>todas</strong> as verificações de Gate em toda a aplicação - não apenas as verificações do painel Clearance. Isto afeta todas as verificações <code>can()</code>, <code>Gate::allows()</code>, e política na sua aplicação, não apenas as que o Clearance define. Para um escopo mais restrito, deixe-o desativado e conceda permissões explicitamente em vez disso.</p></div><h2 id="detecao-de-aliases" tabindex="-1">Deteção de aliases <a class="header-anchor" href="#detecao-de-aliases" aria-label="Permalink to &quot;Deteção de aliases&quot;">​</a></h2><p>Se a sua base de dados já contiver um papel chamado <code>super_admin</code>, <code>superadmin</code>, <code>super-admin</code>, <code>root</code>, ou <code>owner</code>, o instalador deteta-o e pergunta-lhe interativamente se pretende promovê-lo ou criar um <code>super_admin</code> separado. Use <code>--super-admin-role=NAME</code> para saltar o prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">A promoção não é destrutiva</p><p>A promoção renomeia o papel no próprio lugar - todas as atribuições <code>model_has_roles</code> existentes são preservadas via a FK em <code>role_id</code>. Nenhum utilizador perde a sua atribuição de papel existente durante a promoção.</p></div><h2 id="acesso-ao-painel-e-permissoes-de-escrita-granulares" tabindex="-1">Acesso ao Painel e Permissões de Escrita Granulares <a class="header-anchor" href="#acesso-ao-painel-e-permissoes-de-escrita-granulares" aria-label="Permalink to &quot;Acesso ao Painel e Permissões de Escrita Granulares&quot;">​</a></h2><p>Navegue até <code>/clearance</code> após a instalação. O acesso de leitura a todo o painel requer a permissão <code>clearance-access</code>, verificada via <code>can()</code>, nunca <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>As operações de escrita em cada secção são controladas por uma permissão dedicada e delegável - todas criadas pelo <code>clearance:install</code> e atribuídas a <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Permissão</th><th>Controla</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Criar / editar / eliminar permissões</td></tr><tr><td><code>clearance-roles-write</code></td><td>Criar / editar / eliminar papéis e as suas atribuições de permissão</td></tr><tr><td><code>clearance-guards-write</code></td><td>Criar / editar / eliminar guards</td></tr><tr><td><code>clearance-settings-write</code></td><td>Editar metadados de exibição, ícones, cores, papel padrão</td></tr><tr><td><code>clearance-users-write</code></td><td>Atribuir / remover papéis para um utilizador específico</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Conceder acesso restrito</p><p>Combine <code>clearance-access</code> com exatamente uma permissão <code>clearance-{section}-write</code> para dar a um utilizador (por exemplo, um líder de equipa) acesso de escrita a uma única secção do painel - papéis, por exemplo - sem expor as configurações, os guards, ou a gestão de utilizadores.</p></div><p>Se uma linha de permissão granular não existir de todo na base de dados (um estado legado anterior à semeadura), a verificação recorre a <code>clearance-access</code> para compatibilidade retroativa. Em qualquer instância que já tenha executado <code>clearance:install</code>, este fallback nunca é ativado.</p><h2 id="permissoes-clearance-reservadas" tabindex="-1">Permissões <code>clearance-*</code> reservadas <a class="header-anchor" href="#permissoes-clearance-reservadas" aria-label="Permalink to &quot;Permissões \`clearance-*\` reservadas&quot;">​</a></h2><p>As permissões <code>clearance-*</code> são reservadas: não podem ser criadas, renomeadas, eliminadas, ou adicionadas a qualquer papel, exceto através do próprio fluxo de instalação do pacote - mesmo por um ator <code>super_admin</code> para o próprio papel <code>super_admin</code>.</p><h2 id="proximos-passos" tabindex="-1">Próximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos passos&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/features/permissions.html">Permissões</a> - o painel CRUD de permissões geral (exclui <code>clearance-*</code>).</li><li><a href="/clearance-docs/pt/features/roles.html">Papéis</a> - atribuir permissões <code>clearance-*-write</code> a um papel personalizado.</li><li><a href="/clearance-docs/pt/guide/security.html">Segurança</a> - o modelo completo de escalonamento de privilégios e teto.</li></ul>`,24)])])}const m=e(t,[["render",r]]);export{u as __pageData,m as default};
